sql:
SELECT COUNT(DISTINCT m.patient_id) AS total_patient_count
FROM medical_history m
JOIN treatment_records t ON m.patient_id = t.patient_id;

external_knowledge:
- 'Top three studies' refers to the studies with the highest number of participants;
- 'Most frequented gardens' is a metaphor for the studies with the highest participant counts;
- 'Participant counts' represent the number of patients involved in each study.

sql:
SELECT AVG(exam_count) AS average_exams_per_patient
FROM (
  SELECT patient_id, COUNT(exam_id) AS exam_count
  FROM periodontal_exams
  GROUP BY patient_id
);

external_knowledge:
